```class Solution {
    public long minSumSquareDiff(int[] nums1, int[] nums2, int k1, int k2) {
        int n = nums1.length;
        int sum1 = 0;
        int sum2 = 0;

        for (int i = 0; i < n; i++) {
            sum1 += Math.pow(nums1[i], 2);
            sum2 += Math.pow(nums2[i], 2);
        }

        int diff = Math.min(Math.min(sum1, sum2));

        for (int i = 0; i < n; i++) {
            if (Math.abs(nums1[i]) <= k1 && Math.abs(nums2[i]) <= k2) {
                diff = Math.min(diff, Math.pow(Math.abs(nums1[i]), 2) + Math.pow(Math.abs(nums2[i]), 2);
        }
        return diff;
    }
}
